export default function ProductsSection({ onAddToCart }) {
  const [activeTab, setActiveTab] = useState('All');

  const filtered = activeTab === 'All'
    ? ALL_PRODUCTS
    : ALL_PRODUCTS.filter(p => p.category === activeTab);

  return (
    <section style={{
      padding: 'clamp(24px, 4vw, 20px) clamp(12px, 3vw, 60px) clamp(40px, 8vw, 80px)',
      background: '#f8f4e9',
    }}>
      <h2 style={{
        fontFamily: "'Cormorant Garamond', serif",
        fontSize: 'clamp(24px, 5vw, 36px)',
        fontWeight: 400,
        color: '#111111',
        textAlign: 'center',
        marginBottom: 8,
        textTransform: 'uppercase',
        letterSpacing: '0.08em',
      }}>
        Our Chandelier Collection
      </h2>

      <div style={{
        display: 'flex',
        justifyContent: 'center',
        overflowX: 'auto',
        WebkitOverflowScrolling: 'touch',
        gap: 'clamp(12px, 2vw, 24px)',
        marginBottom: 'clamp(24px, 4vw, 32px)',
        padding: '8px 0',
      }}>
        {TABS.map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            style={{
              padding: '8px 16px',
              background: 'none',
              border: 'none',
              borderBottom: `2px solid ${activeTab === tab ? '#000000' : 'transparent'}`,
              color: activeTab === tab ? '#000000' : '#888888',
              cursor: 'pointer',
              fontFamily: "'Jost', sans-serif",
              fontSize: '13px',
              textTransform: 'uppercase',
              letterSpacing: '0.1em',
              whiteSpace: 'nowrap',
              transition: 'all 0.3s ease',
            }}
          >
            {tab}
          </button>
        ))}
      </div>

      <ProductCardList products={filtered} onAddToCart={onAddToCart} />
    </section>
  );
}